import 'package:flutter_fractals/core/models/export_options.dart';
import 'package:flutter_fractals/features/export/custom_export_dimensions.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('resolveCustomExportDimension', () {
    test('uses positive field text before current value or fallback', () {
      expect(
        resolveCustomExportDimension(
          fieldText: '2048',
          currentValue: 1024,
          fallback: defaultCustomExportWidth,
        ),
        2048,
      );
    });

    test('falls back to current value when field text is invalid', () {
      expect(
        resolveCustomExportDimension(
          fieldText: 'not a number',
          currentValue: 1024,
          fallback: defaultCustomExportWidth,
        ),
        1024,
      );
    });

    test('normalizes oversized field text through export dimension policy', () {
      expect(
        resolveCustomExportDimension(
          fieldText: '${1 << 40}',
          currentValue: null,
          fallback: defaultCustomExportWidth,
        ),
        ExportDimensionPolicy.maxPixelDimension,
      );
    });

    test('normalizes oversized current value fallback through policy', () {
      expect(
        resolveCustomExportDimension(
          fieldText: '',
          currentValue: 1 << 40,
          fallback: defaultCustomExportWidth,
        ),
        ExportDimensionPolicy.maxPixelDimension,
      );
    });
  });

  group('resolveCustomExportDimensionPlan', () {
    test('exposes winning source and clamp provenance', () {
      final clampedField = resolveCustomExportDimensionPlan(
        fieldText: '${1 << 40}',
        currentValue: 1024,
        fallback: defaultCustomExportWidth,
      );
      final currentFallback = resolveCustomExportDimensionPlan(
        fieldText: '0',
        currentValue: 1024,
        fallback: defaultCustomExportWidth,
      );

      expect(clampedField.value, ExportDimensionPolicy.maxPixelDimension);
      expect(clampedField.source, CustomExportDimensionSource.fieldText);
      expect(clampedField.wasClamped, isTrue);
      expect(currentFallback.value, 1024);
      expect(currentFallback.source, CustomExportDimensionSource.currentValue);
      expect(currentFallback.wasClamped, isFalse);
    });
  });

  group('withResolvedCustomExportDimensions', () {
    test('stores normalized custom dimensions in the export payload', () {
      final resolved = withResolvedCustomExportDimensions(
        options: const ExportOptions(
          resolution: ExportResolution.custom,
          customWidth: 1 << 40,
          customHeight: 720,
        ),
        widthText: '',
        heightText: '${1 << 35}',
      );

      expect(resolved.customWidth, ExportDimensionPolicy.maxPixelDimension);
      expect(resolved.customHeight, ExportDimensionPolicy.maxPixelDimension);
    });
  });
}

import 'package:equatable/equatable.dart';
import 'package:vector_math/vector_math.dart';

/// Represents the complete rendering parameters for a fractal.
///
/// This class encapsulates all configurable options that affect how a fractal
/// is rendered, including mathematical parameters (power, iterations, bailout),
/// visual settings (color scheme, zoom), and spatial transformations (rotation).
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final params = FractalParams(
///   power: 8.0,
///   iterations: 100,
///   zoom: 2.0,
///   rotation: Vector3(0.5, 0.3, 0.0),
///   mousePos: Vector2.zero(),
/// );
/// ```
class FractalParams extends Equatable {
  /// The mathematical power used in fractal calculations.
  ///
  /// Higher values create more intricate patterns. For Mandelbulb fractals,
  /// values of 8 produce the classic shape, while lower or higher values
  /// create interesting variations.
  ///
  /// Typical range: 2.0 to 12.0
  final double power;

  /// The maximum number of iterations for escape-time calculations.
  ///
  /// Higher iteration counts reveal more detail but require more computation.
  /// Values between 50-200 are typical for interactive rendering.
  final int iterations;

  /// The escape radius threshold for fractal calculations.
  ///
  /// Points that exceed this distance from the origin are considered to have
  /// escaped. Lower values create sharper boundaries.
  ///
  /// Typical range: 1.0 to 4.0
  final double bailout;

  /// The current zoom/magnification level.
  ///
  /// Values greater than 1.0 zoom in, values less than 1.0 zoom out.
  /// Range is typically clamped to 0.1x - 10x.
  final double zoom;

  /// The 3D rotation angles for the fractal view.
  ///
  /// Used for 3D fractals (like Mandelbulb) to control camera orientation.
  /// Each component represents rotation around the X, Y, and Z axes respectively.
  final Vector3 _rotation;

  /// Returns a defensive copy because [Vector3] is mutable.
  Vector3 get rotation => Vector3.copy(_rotation);

  /// The active color scheme index.
  ///
  /// Maps to [AppColorScheme] enum values:
  /// - 0: Fire
  /// - 1: Ocean
  /// - 2: Psychedelic
  /// - 3: Grayscale
  final int colorScheme;

  /// The current mouse/touch position in normalized coordinates.
  ///
  /// Used for interactive effects where the fractal responds to pointer position.
  final Vector2 _mousePos;

  /// Returns a defensive copy because [Vector2] is mutable.
  Vector2 get mousePos => Vector2.copy(_mousePos);

  /// The type of fractal being rendered.
  ///
  /// Determines which algorithm is used for fractal generation.
  final FractalType fractalType;

  /// Creates a new [FractalParams] instance with the specified values.
  ///
  /// The [rotation] and [mousePos] vectors are required as they have no
  /// sensible universal default.
  FractalParams({
    this.power = 8.0,
    this.iterations = 50,
    this.bailout = 2.0,
    this.zoom = 1.0,
    required Vector3 rotation,
    this.colorScheme = 0,
    required Vector2 mousePos,
    this.fractalType = FractalType.mandelbulb,
  })  : _rotation = Vector3.copy(rotation),
        _mousePos = Vector2.copy(mousePos);

  /// Creates a [FractalParams] with sensible default values.
  ///
  /// Useful for initialization when no specific parameters are needed.
  FractalParams.withDefaults()
      : power = 8.0,
        iterations = 50,
        bailout = 2.0,
        zoom = 1.0,
        _rotation = Vector3(0.0, 0.0, 0.0),
        colorScheme = 0,
        _mousePos = Vector2(0.0, 0.0),
        fractalType = FractalType.mandelbulb;

  /// Creates a copy of this [FractalParams] with the given fields replaced.
  ///
  /// All parameters are optional; unspecified parameters retain their
  /// original values.
  FractalParams copyWith({
    double? power,
    int? iterations,
    double? bailout,
    double? zoom,
    Vector3? rotation,
    int? colorScheme,
    Vector2? mousePos,
    FractalType? fractalType,
  }) {
    return FractalParams(
      power: power ?? this.power,
      iterations: iterations ?? this.iterations,
      bailout: bailout ?? this.bailout,
      zoom: zoom ?? this.zoom,
      rotation: rotation ?? _rotation,
      colorScheme: colorScheme ?? this.colorScheme,
      mousePos: mousePos ?? _mousePos,
      fractalType: fractalType ?? this.fractalType,
    );
  }

  @override
  List<Object?> get props => [
        power,
        iterations,
        bailout,
        zoom,
        _rotation,
        colorScheme,
        _mousePos,
        fractalType,
      ];
}

/// Available color schemes for fractal rendering.
///
/// Each scheme provides a distinct visual aesthetic for the fractal output.
enum AppColorScheme {
  /// Warm orange-red-yellow gradient, reminiscent of flames.
  fire,

  /// Cool blue-teal gradient, evoking underwater themes.
  ocean,

  /// Vibrant multi-color gradient with high saturation.
  psychedelic,

  /// Black-to-white gradient for a classic mathematical look.
  grayscale;
}

/// Types of fractals available for rendering.
///
/// Each type uses a different mathematical algorithm to generate
/// its characteristic patterns.
enum FractalType {
  /// 3D extension of the Mandelbrot set.
  ///
  /// Creates a bulbous, organic-looking 3D shape through
  /// spherical coordinate mapping.
  mandelbulb,

  /// Box-folding fractal with recursive transformations.
  ///
  /// Creates geometric, box-like structures with infinite detail.
  mandelbox,

  /// Complex-number iteration fractal.
  ///
  /// Uses a constant complex parameter to create varied 2D patterns.
  julia,

  /// Recursive tetrahedron subdivision.
  ///
  /// A 3D fractal created by iteratively removing tetrahedra
  /// from a larger tetrahedron.
  sierpinski;
}

import 'package:flutter_fractals/core/models/fractal_params.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart';

void main() {
  group('FractalParams', () {
    test('equality includes fractalType', () {
      final a = FractalParams(
        rotation: Vector3.zero(),
        mousePos: Vector2.zero(),
        fractalType: FractalType.mandelbulb,
      );
      final b = a.copyWith(fractalType: FractalType.julia);

      expect(a, isNot(equals(b)));
    });

    test('snapshots mutable vectors supplied by callers', () {
      final rotation = Vector3(0.1, 0.2, 0.3);
      final mousePos = Vector2(0.4, 0.5);
      final params = FractalParams(rotation: rotation, mousePos: mousePos);

      rotation.setValues(1.0, 2.0, 3.0);
      mousePos.setValues(4.0, 5.0);

      expect(params.rotation, Vector3(0.1, 0.2, 0.3));
      expect(params.mousePos, Vector2(0.4, 0.5));
    });

    test('exposes vector fields as immutable snapshots', () {
      final params = FractalParams(
        rotation: Vector3(0.1, 0.2, 0.3),
        mousePos: Vector2(0.4, 0.5),
      );

      final exposedRotation = params.rotation;
      final exposedMousePos = params.mousePos;
      exposedRotation.setValues(1.0, 2.0, 3.0);
      exposedMousePos.setValues(4.0, 5.0);

      expect(params.rotation, Vector3(0.1, 0.2, 0.3));
      expect(params.mousePos, Vector2(0.4, 0.5));
    });

    test('copyWith snapshots replacement vectors', () {
      final original = FractalParams(
        rotation: Vector3.zero(),
        mousePos: Vector2.zero(),
      );
      final replacementRotation = Vector3(0.1, 0.2, 0.3);
      final replacementMousePos = Vector2(0.4, 0.5);

      final copy = original.copyWith(
        rotation: replacementRotation,
        mousePos: replacementMousePos,
      );

      replacementRotation.setValues(1.0, 2.0, 3.0);
      replacementMousePos.setValues(4.0, 5.0);

      expect(copy.rotation, Vector3(0.1, 0.2, 0.3));
      expect(copy.mousePos, Vector2(0.4, 0.5));
      expect(original.rotation, Vector3.zero());
      expect(original.mousePos, Vector2.zero());
    });
  });
}

