import 'package:vector_math/vector_math.dart';

/// Represents the view/camera state for fractal rendering.
///
/// This class captures the user's navigation state within a fractal:
/// - For 2D fractals: pan offset and zoom level
/// - For 3D fractals: rotation angles and zoom level
///
/// [FractalViewState] is designed to be stored in presets and serialized,
/// allowing users to save and restore specific viewpoints.
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final view = FractalViewState(
///   pan: Vector2(-0.5, 0.2),  // Offset from center
///   zoom: 3.0,                 // 3x magnification
///   rotation: Vector3.zero(), // No rotation (for 2D)
/// );
/// ```
class FractalViewState {
  /// The 2D pan offset from the fractal center.
  ///
  /// For 2D fractals, this determines which part of the complex plane
  /// is visible. Positive X moves right, positive Y moves down.
  ///
  /// Typical range: -3.0 to 3.0 for each axis.
  final Vector2 _pan;

  /// Returns a defensive copy because [Vector2] is mutable.
  Vector2 get pan => Vector2.copy(_pan);

  /// The current zoom/magnification level.
  ///
  /// - Values > 1.0 zoom in (magnify)
  /// - Values < 1.0 zoom out (shrink)
  /// - Value of 1.0 is the default view
  ///
  /// In controller updates, this is typically clamped to [1e-9, 1e12]
  /// to allow deep-zoom workflows.
  final double zoom;

  /// The 3D rotation angles in radians.
  ///
  /// For 3D fractals like Mandelbulb, this controls the camera orientation:
  /// - x: Rotation around the X axis (pitch)
  /// - y: Rotation around the Y axis (yaw)
  /// - z: Rotation around the Z axis (roll)
  ///
  /// For 2D fractals, this is typically [Vector3.zero()].
  final Vector3 _rotation;

  /// Returns a defensive copy because [Vector3] is mutable.
  Vector3 get rotation => Vector3.copy(_rotation);

  /// Creates a [FractalViewState] with specific view parameters.
  ///
  /// All parameters are required to define a complete view state. The supplied
  /// vector instances are copied because [Vector2] and [Vector3] are mutable.
  FractalViewState({
    required Vector2 pan,
    required this.zoom,
    required Vector3 rotation,
  })  : _pan = Vector2.copy(pan),
        _rotation = Vector3.copy(rotation);

  /// Creates the initial/default view state.
  ///
  /// Centers the view with no pan offset, 1x zoom, and no rotation.
  /// This is the starting point when a fractal is first loaded.
  FractalViewState.initial()
      : _pan = Vector2.zero(),
        zoom = 1.0,
        _rotation = Vector3.zero();

  /// Creates a copy of this view state with the given fields replaced.
  ///
  /// Unspecified fields retain their original values.
  ///
  /// Example:
  /// ```dart
  /// final zoomed = view.copyWith(zoom: view.zoom * 2);
  /// ```
  FractalViewState copyWith({
    Vector2? pan,
    double? zoom,
    Vector3? rotation,
  }) {
    return FractalViewState(
      pan: pan ?? _pan,
      zoom: zoom ?? this.zoom,
      rotation: rotation ?? _rotation,
    );
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';

void main() {
  group('FractalViewState', () {
    group('initial', () {
      test('creates state with zoom 1.0', () {
        final state = FractalViewState.initial();
        expect(state.zoom, 1.0);
      });

      test('creates state with zero pan', () {
        final state = FractalViewState.initial();
        expect(state.pan.x, 0.0);
        expect(state.pan.y, 0.0);
      });

      test('creates state with zero rotation', () {
        final state = FractalViewState.initial();
        expect(state.rotation.x, 0.0);
        expect(state.rotation.y, 0.0);
        expect(state.rotation.z, 0.0);
      });
    });

    group('copyWith', () {
      test('replaces only zoom when specified', () {
        final original = FractalViewState.initial();
        final copy = original.copyWith(zoom: 3.5);

        expect(copy.zoom, 3.5);
        expect(copy.pan.x, original.pan.x);
        expect(copy.pan.y, original.pan.y);
        expect(copy.rotation.x, original.rotation.x);
        expect(copy.rotation.y, original.rotation.y);
        expect(copy.rotation.z, original.rotation.z);
      });

      test('replaces only pan when specified', () {
        final original = FractalViewState.initial();
        final newPan = Vector2(1.5, -0.5);
        final copy = original.copyWith(pan: newPan);

        expect(copy.pan.x, 1.5);
        expect(copy.pan.y, -0.5);
        expect(copy.zoom, original.zoom);
        expect(copy.rotation.x, original.rotation.x);
      });

      test('replaces only rotation when specified', () {
        final original = FractalViewState.initial();
        final newRotation = Vector3(0.1, 0.2, 0.3);
        final copy = original.copyWith(rotation: newRotation);

        expect(copy.rotation.x, closeTo(0.1, 1e-6));
