import 'dart:io';

import 'package:flutter_test/flutter_test.dart';

import 'support/shader_asset_expectations.dart';

void main() {
  group('legacy shader assets', () {
    const legacyShaderAssets = <String>[
      'shaders/legacy/diagnostics/mandelbrot.frag',
      'shaders/legacy/diagnostics/mandelbrot_hardgrad.frag',
      'shaders/legacy/diagnostics/mandelbrot_simple.frag',
      'shaders/legacy/escape_time/burning_ship.frag',
      'shaders/legacy/escape_time/julia.frag',
      'shaders/legacy/escape_time/mandel_step_escape.frag',
      'shaders/legacy/escape_time/mandel_step_smooth.frag',
      'shaders/legacy/escape_time/mandelbrot_et.frag',
      'shaders/legacy/escape_time/mandelbrot_tex.frag',
      'shaders/legacy/escape_time/phoenix.frag',
      'shaders/legacy/precision/mandelbrot_df2.frag',
      'shaders/legacy/raymarched_3d/mandelbulb.frag',
    ];

    test('declared legacy asset paths exist under responsibility folders', () {
      final declaredShaderAssets = loadDeclaredShaderAssets();
      final declaredLegacyShaderAssets = declaredShaderAssets
          .where((asset) => asset.startsWith('shaders/legacy/'))
          .toList()
        ..sort();

      expect(declaredLegacyShaderAssets, orderedEquals(legacyShaderAssets));
      expectAssetsDeclaredAndExist(
        legacyShaderAssets,
        declaredShaderAssets,
        fileReason: 'must stay at its declared legacy responsibility path',
      );
    });

    test('legacy root contains no fragment shaders', () {
      final rootFragmentFiles = Directory('shaders/legacy')
          .listSync()
          .whereType<File>()
          .where((file) => file.path.endsWith('.frag'))
          .map((file) => file.uri.pathSegments.last)
          .toList()
        ..sort();

      expect(
        rootFragmentFiles,
        isEmpty,
        reason: 'legacy shaders belong in responsibility subfolders, not root',
      );
    });
  });
}

import 'package:flutter_fractals/core/modules/builders/raymarched_3d_catalog.dart';
import 'package:flutter_test/flutter_test.dart';

import '../support/shader_asset_expectations.dart';

void main() {
  const shaderRoot = 'shaders/3d_and_hypercomplex/';
  late final Set<String> declaredShaderAssets;

  setUpAll(() {
    declaredShaderAssets = loadDeclaredShaderAssets();
  });

  test('declared 3D and hypercomplex shader assets exist on disk', () {
    final assets =
        declaredShaderAssetsStartingWith(declaredShaderAssets, shaderRoot);

    expect(assets, isNotEmpty);
    expectAssetsExist(assets);
  });

  test('catalog 3D and hypercomplex shader assets are declared in pubspec', () {
    final catalogAssets = [
      ...escapeTimeShaderAssetsStartingWith(shaderRoot),
      ...raymarched3DCatalog
          .map((module) => module.shaderAsset)
          .where((asset) => asset.startsWith(shaderRoot)),
    ]..sort();

    expect(catalogAssets, isNotEmpty);
    expectAssetsDeclaredAndExist(catalogAssets, declaredShaderAssets);
  });
}

import 'dart:io';

import 'package:flutter_fractals/core/modules/builders/escape_time_catalog.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:yaml/yaml.dart';

Set<String> loadDeclaredShaderAssets() {
  final pubspec = loadYaml(File('pubspec.yaml').readAsStringSync()) as YamlMap;
  final flutter = pubspec['flutter'] as YamlMap;
  return (flutter['shaders'] as YamlList).cast<String>().toSet();
}

List<String> escapeTimeShaderAssetsStartingWith(String shaderRoot) {
  return escapeTimeCatalog
      .map((config) => config.shaderAsset)
      .where((asset) => asset.startsWith(shaderRoot))
      .toList()
    ..sort();
}

List<String> declaredShaderAssetsStartingWith(
  Set<String> declaredShaderAssets,
  String shaderRoot,
) {
  return declaredShaderAssets
      .where((asset) => asset.startsWith(shaderRoot))
      .toList()
    ..sort();
}

void expectAssetsExist(Iterable<String> assets,
    {String fileReason = 'must exist'}) {
  for (final asset in assets) {
    expect(File(asset).existsSync(), isTrue, reason: '$asset $fileReason');
  }
}

void expectAssetsDeclaredAndExist(
  Iterable<String> assets,
  Set<String> declaredShaderAssets, {
  String fileReason = 'must exist',
}) {
  for (final asset in assets) {
    expect(declaredShaderAssets, contains(asset),
        reason: '$asset must be declared');
    expect(File(asset).existsSync(), isTrue, reason: '$asset $fileReason');
  }
}

